import { apiClient, unwrap } from '@linm-soft/common-components';
import type { BffResponse } from '@linm-soft/common-components';
import type { SystemSettingsApiDto, SystemSettingsFormDto } from './settingsMapper';
import { mapSystemSettingsFromApi, mapSystemSettingsToApi } from './settingsMapper';
import type { UpdateVoucherCodeFormatDto, VoucherCodeFormatDto } from './voucherCodeFormatModels';
import type { UpdateVoucherRegistryDto, VoucherRegistryDto } from './voucherRegistryModels';
import type {
  ProcessingLevelDto,
  UpdateProcessingLevelsDto,
} from './processingLevelModels';

const BASE = '/system';

function buildQs(params: Record<string, string | number | boolean | undefined>) {
  const qs = new URLSearchParams();
  Object.entries(params).forEach(([k, v]) => {
    if (v !== undefined && v !== '') qs.set(k, String(v));
  });
  return qs.toString();
}

export const systemEndpoint = {
  getSettings: async (): Promise<SystemSettingsFormDto | undefined> => {
    const res = await apiClient.get<BffResponse<SystemSettingsApiDto>>(`${BASE}/settings`);
    const data = unwrap(res);
    return data ? mapSystemSettingsFromApi(data) : undefined;
  },

  saveSettings: async (dto: SystemSettingsFormDto) => {
    const body = mapSystemSettingsToApi(dto);
    const res = await apiClient.put<BffResponse<SystemSettingsApiDto>>(`${BASE}/settings`, body);
    const data = unwrap(res);
    return data ? mapSystemSettingsFromApi(data) : undefined;
  },

  getVoucherCodeFormats: async () => {
    const res = await apiClient.get<BffResponse<VoucherCodeFormatDto[]>>(`${BASE}/voucher-code-formats`);
    return unwrap(res) ?? [];
  },

  updateVoucherCodeFormat: async (id: string, dto: UpdateVoucherCodeFormatDto) => {
    const res = await apiClient.put<BffResponse<VoucherCodeFormatDto>>(
      `${BASE}/voucher-code-formats/${id}`,
      dto,
    );
    return unwrap(res);
  },

  getVoucherRegistry: async () => {
    const res = await apiClient.get<BffResponse<VoucherRegistryDto[]>>(`${BASE}/voucher-registry`);
    return unwrap(res) ?? [];
  },

  updateVoucherRegistry: async (voucherTypeCode: string, dto: UpdateVoucherRegistryDto) => {
    const res = await apiClient.put<BffResponse<VoucherRegistryDto>>(
      `${BASE}/voucher-registry/${encodeURIComponent(voucherTypeCode)}`,
      dto,
    );
    return unwrap(res);
  },

  getProcessingLevels: async (ledgerKind: string) => {
    const qs = buildQs({ ledgerKind });
    const res = await apiClient.get<BffResponse<ProcessingLevelDto[]>>(
      `${BASE}/processing-levels?${qs}`,
    );
    return unwrap(res) ?? [];
  },

  updateProcessingLevels: async (ledgerKind: string, dto: UpdateProcessingLevelsDto) => {
    const qs = buildQs({ ledgerKind });
    const res = await apiClient.put<BffResponse<ProcessingLevelDto[]>>(
      `${BASE}/processing-levels?${qs}`,
      dto,
    );
    return unwrap(res) ?? [];
  },
};
